import { useQuery } from '@tanstack/react-query';
import React, { useEffect, useState } from 'react'
import { Img_URL, fetchMovie } from '../../utils/fetchApi';
import { Link } from 'react-router-dom';
import  "../MovieCategory/popular.scss"
const Popular = () => {

    const [page,setPage]=useState(1);
    const[popularList,setPopularlist]=useState([]);


   const handleInfiniteScroll=async()=>{
     if(window.innerHeight + document.documentElement.scrollTop + 1 >= document.documentElement.scrollHeight ){
      setPage((prev)=> prev + 1);
     }
   }

    useEffect(()=>{
      window.addEventListener('Scroll',handleInfiniteScroll);
      return()=> window.removeEventListener('Scroll', handleInfiniteScroll);
    },[])



    const { isLoading,isError,error,data} = useQuery({
        queryKey: ["Movie"],
        keepPreviousData: true,
        queryFn: () =>
          fetchMovie("popular",`${page}`).then((res) => 
             setPopularlist((prev)=> [...prev,...res.results])
          ),
      });





      if (isLoading) {
        return (
          <div className="loading">
            <h1>Loading...</h1>
          </div>
        );
      } else if (isError) {
        return (
          <div className="error">
            <p>{error.message}</p>
          </div>
        );
      } else
  return (
    <div className="Popular">
          <h1>Popular Movies</h1>
          <div>
          {popularList?.map((item) => (
              <Link to={`/movie/${item.id}`} className="card" key={item.title}>
                <img src={`${Img_URL}${item.poster_path}`} alt="img" />
              </Link>
          ))}
          </div>
        </div>
  )
}

export default Popular
